def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 0
        if ratio > 1.5:
            for p in range(1, 5):
                penalty += (ratio ** (2 * p + 1)) / (p * 3)
            priorities[i] = (ratio ** 4) + penalty
            if capacity > item * 2:
                priorities[i] /= (capacity / item)
        elif 1 < ratio <= 1.5:
            priorities[i] = (ratio ** 3) * 2
            for q in range(1, 4):
                priorities[i] += ((-1) ** q) * (ratio ** q) / (q + 0.5)
        else:
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                term = sign * (ratio ** j) / (j + 0.2)
                score += term
            if ratio < 0.25:
                multiplier = 20
                for m in range(1, 5):
                    score += (ratio ** m) / (m * 1.5)
            elif ratio < 0.5:
                multiplier = 12
                for m in range(2, 6):
                    score += -((ratio ** m) / (m + 1))
            elif ratio < 0.75:
                multiplier = 7
                for m in range(1, 5):
                    if m % 2 == 0:
                        score += (ratio ** m) / (m + 0.5)
                    else:
                        score -= (ratio ** m) / (m + 0.5)
            else:
                multiplier = 3
                for m in range(3, 7):
                    score += ((-1) ** m) * (ratio ** m) / (m + 1)
                if ratio > 0.9:
                    extra = 0
                    for n in range(1, 5):
                        extra += (ratio ** n) / (n + 0.3)
                    score += extra
            priorities[i] = abs(score) * multiplier
        if capacity == item:
            priorities[i] += 5
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
